#include <iostream>

void printRectangleStats(int width, int height) {
    std::cout << "Width: " << width << '\n';
    std::cout << "Height: " << height << '\n';
    std::cout << "Area: " << width * height << '\n';
}

int main() {
    int width {}, height {};
    std::cin >> width >> height;

    printRectangleStats(width, height);

    return 0;
}

