solution_code:
#include <iostream>

int computeSum(int a, int b, int c) {
    return a + b + c;
}

int computeProduct(int a, int b, int c) {
    return a * b * c;
}

void printReport(int sum, int product, int average) {
    std::cout << "Sum: " << sum << '\n';
    std::cout << "Product: " << product << '\n';
    std::cout << "Average (int): " << average << '\n';
}

int main() {
    int a {}, b {}, c {};
    std::cin >> a >> b >> c;

    int sum { computeSum(a, b, c) };
    int product { computeProduct(a, b, c) };
    int average { sum / 3 };
    printReport(sum, product, average);

    return 0;
}
